package com.company.supervision.infrastructure.repository.organization;import org.apache.ibatis.annotations.*;import java.util.*;@Mapper public interface PersonDepartmentMapper{@Delete("DELETE FROM supervision_person_department WHERE person_id=#{personId}")int deleteForPerson(Long personId);@Insert("INSERT IGNORE INTO supervision_person_department(person_id,department_id,is_main) VALUES(#{personId},#{departmentId},#{main})")int link(Long personId,Long departmentId,int main);@Select("SELECT department_id FROM supervision_person_department WHERE person_id=#{personId} ORDER BY is_main DESC,department_id")List<Long>departmentsForPerson(Long personId);@Select("SELECT COUNT(*) FROM supervision_person_department WHERE department_id=#{departmentId}")long countByDepartment(Long departmentId);}
